selector_to_html = {"a[href=\"motion_correction.html#logging\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.2. </span>Logging<a class=\"headerlink\" href=\"#logging\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#caiman-docs-on-component-eval\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">12. </span>Caiman docs on component eval<a class=\"headerlink\" href=\"#caiman-docs-on-component-eval\" title=\"Permalink to this heading\">#</a></h1><p>https://caiman.readthedocs.io/en/latest/Getting_Started.html#component-evaluation</p>", "a[href=\"motion_correction.html#registration-grid-search-if-you-need-it\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">7. </span>Registration Grid Search (if you need it!)<a class=\"headerlink\" href=\"#registration-grid-search-if-you-need-it\" title=\"Permalink to this heading\">#</a></h1><p>More runs with varying parameters, stored on disk in the dataframe batch.pickle</p>", "a[href=\"collation.html#get-outputs-for-each-z-plane\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25.1. </span>Get outputs for each z-plane<a class=\"headerlink\" href=\"#get-outputs-for-each-z-plane\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"assembly.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1. </span>LBM Step 1: Image Assembly<a class=\"headerlink\" href=\"#lbm-step-1-image-assembly\" title=\"Permalink to this heading\">#</a></h1><p>Raw ScanImage .tiff files are saved to disk in an interleaved manner.</p>", "a[href=\"collation.html#combine-results-of-different-z-planes\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25.3. </span>Combine results of different z_planes<a class=\"headerlink\" href=\"#combine-results-of-different-z-planes\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"fastplotlib.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">26. </span>Fastplotlib Examples<a class=\"headerlink\" href=\"#fastplotlib-examples\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">26.1. </span>Smoothing with Gaussian Filter<a class=\"headerlink\" href=\"#smoothing-with-gaussian-filter\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#cnmf-outputs\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">16. </span>CNMF outputs<a class=\"headerlink\" href=\"#cnmf-outputs\" title=\"Permalink to this heading\">#</a></h1><p>Similar to mcorr, you can use the <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> API to fetch the outputs.</p><p><a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/api/cnmf.html\">API reference for mesmerize-CNMF</a>\n<a class=\"reference external\" href=\"https://caiman.readthedocs.io/en/latest/Getting_Started.html#parameters\">API reference for caiman-CNMF</a></p>", "a[href=\"segmentation.html#check-for-an-error\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">15.1. </span>Check for an error<a class=\"headerlink\" href=\"#check-for-an-error\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#reconstructed-background-b-f\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">19. </span>Reconstructed background - <code class=\"docutils literal notranslate\"><span class=\"pre\">b</span> <span class=\"pre\">*</span> <span class=\"pre\">f</span></code><a class=\"headerlink\" href=\"#reconstructed-background-b-f\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"segmentation.html#cnmf-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">16.1. </span>CNMF Object<a class=\"headerlink\" href=\"#cnmf-object\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#data-paths-todo\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">13. </span>Data Paths (TODO)<a class=\"headerlink\" href=\"#data-paths-todo\" title=\"Permalink to this heading\">#</a></h1><p>The batch folder gets fairly cluttered with memmory mapped files.\nThis needs some cleaning before putting into tree form.</p>", "a[href=\"collation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25. </span>LBM Step 4: Collate Planes<a class=\"headerlink\" href=\"#lbm-step-4-collate-planes\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">25.1. </span>Get outputs for each z-plane<a class=\"headerlink\" href=\"#get-outputs-for-each-z-plane\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"preprocessing.html#percentile-filtering\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3.1. </span>Percentile Filtering<a class=\"headerlink\" href=\"#percentile-filtering\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html#distinguishing-parameter-variants\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">8. </span>Distinguishing parameter variants<a class=\"headerlink\" href=\"#distinguishing-parameter-variants\" title=\"Permalink to this heading\">#</a></h1><p>We can see that there are many parameter variants, but it is not easy to see the differences in parameters between the rows that have the same <code class=\"docutils literal notranslate\"><span class=\"pre\">item_name</span></code>.</p><p>We can use the <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman.get_params_diffs()</span></code> to see the unique parameters between rows with the same <code class=\"docutils literal notranslate\"><span class=\"pre\">item_name</span></code></p>", "a[href=\"segmentation.html#residuals-y-ac-bf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">20. </span>Residuals - <code class=\"docutils literal notranslate\"><span class=\"pre\">Y</span> <span class=\"pre\">-</span> <span class=\"pre\">AC</span> <span class=\"pre\">-</span> <span class=\"pre\">bf</span></code><a class=\"headerlink\" href=\"#residuals-y-ac-bf\" title=\"Permalink to this heading\">#</a></h1><p>Mesmerize-core provides these outputs as lazy arrays. This allows you to work with arrays that would otherwise be hundreds of gigabytes or terabytes in size.</p>", "a[href=\"motion_correction.html#default-registration-parameters\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5. </span>Default registration parameters<a class=\"headerlink\" href=\"#default-registration-parameters\" title=\"Permalink to this heading\">#</a></h1><p>The parameters are passed <strong>directly</strong> to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>, this means you need to use the same exact names for the parameters and you can use all the parameters that you can use with <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code> - because it\u2019s just passing them to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p><p>The parameters dict for a mesmerize batch item must have the following structure. Put all the parameters in a dict under a key called <strong>main</strong>. The <strong>main</strong> dict is then fed directly to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p>", "a[href=\"collation.html#align-each-plane-to-the-reference-plane\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25.5. </span>1. Align each plane to the reference plane<a class=\"headerlink\" href=\"#align-each-plane-to-the-reference-plane\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"assembly.html#steps\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.1. </span>Steps:<a class=\"headerlink\" href=\"#steps\" title=\"Permalink to this heading\">#</a></h2><p><strong>1a.</strong> Set up filepaths.</p><p><strong>1b.</strong> Initialize a <a class=\"reference external\" href=\"https://github.com/atlab/scanreader/tree/master\">scanreader</a> object to read in raw .tiff files.</p>", "a[href=\"fastplotlib.html#preview-raw-traces\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">26.2. </span>Preview \u2018raw traces\u2019<a class=\"headerlink\" href=\"#preview-raw-traces\" title=\"Permalink to this heading\">#</a></h2><p>Show the raw trace for a given pixel by clicking on that pixel.</p>", "a[href=\"segmentation.html#parameter-gridsearch\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">22. </span>Parameter Gridsearch<a class=\"headerlink\" href=\"#parameter-gridsearch\" title=\"Permalink to this heading\">#</a></h1><p>As shown for motion correction, the purpose of <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> is to perform parameter searches</p>", "a[href=\"preprocessing.html#scan-phase-correction\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3. </span>Scan-phase correction<a class=\"headerlink\" href=\"#scan-phase-correction\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">3.1. </span>Percentile Filtering<a class=\"headerlink\" href=\"#percentile-filtering\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html#correlation-metrics\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9.1. </span>Correlation metrics<a class=\"headerlink\" href=\"#correlation-metrics\" title=\"Permalink to this heading\">#</a></h2><p>Create a couple of summary images of the movie, including:</p>", "a[href=\"preprocessing.html#threshold-your-movie\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.3. </span>Threshold your movie<a class=\"headerlink\" href=\"#threshold-your-movie\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#segmentation-extract-neuronal-locations-and-planar-time-traces\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">11.1. </span>Segmentation: Extract neuronal locations and planar time-traces.<a class=\"headerlink\" href=\"#segmentation-extract-neuronal-locations-and-planar-time-traces\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#interactive-parameter-exploration\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">17. </span>Interactive Parameter Exploration<a class=\"headerlink\" href=\"#interactive-parameter-exploration\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">17.1. </span>Temporal components, residuals<a class=\"headerlink\" href=\"#temporal-components-residuals\" title=\"Permalink to this heading\">#</a></h2><p>Many of the cnmf functions take a rich set of arguments</p>", "a[href=\"collation.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25.6. </span>2. Align each plane to the reference plane<a class=\"headerlink\" href=\"#id1\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html#user-input-input-data-path-and-plane-number\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.4. </span>User input: input data path and plane number<a class=\"headerlink\" href=\"#user-input-input-data-path-and-plane-number\" title=\"Permalink to this heading\">#</a></h2><p>the same path as <span class=\"xref myst\">pre_processing</span>\nparent_dir = Path().home() / \u2018caiman_data\u2019 / \u2018animal_01\u2019 / \u2018session_01\u2019</p>", "a[href=\"segmentation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">11. </span>LBM Step 3: Segmentation<a class=\"headerlink\" href=\"#lbm-step-3-segmentation\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">11.1. </span>Segmentation: Extract neuronal locations and planar time-traces.<a class=\"headerlink\" href=\"#segmentation-extract-neuronal-locations-and-planar-time-traces\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html#pixel-shifts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9.2. </span>Pixel Shifts<a class=\"headerlink\" href=\"#pixel-shifts\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"fastplotlib.html#smoothing-with-gaussian-filter\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">26.1. </span>Smoothing with Gaussian Filter<a class=\"headerlink\" href=\"#smoothing-with-gaussian-filter\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html#optional-view-hardware-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.3. </span>(optional): View hardware information<a class=\"headerlink\" href=\"#optional-view-hardware-information\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"preprocessing.html#save-as-tiff-zarr\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.2. </span>Save as <code class=\"docutils literal notranslate\"><span class=\"pre\">.tiff</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">.zarr</span></code><a class=\"headerlink\" href=\"#save-as-tiff-zarr\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html#first-registration-run-preset-with-good-defaults\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6. </span>First registration run: preset with good defaults<a class=\"headerlink\" href=\"#first-registration-run-preset-with-good-defaults\" title=\"Permalink to this heading\">#</a></h1><p>Technical notes: On Linux &amp; Mac it will run in subprocess but on Windows it will run in the local kernel.</p>", "a[href=\"motion_correction.html#registration-correct-for-rigid-non-rigid-movement\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.1. </span>Registration: Correct for rigid/non-rigid movement<a class=\"headerlink\" href=\"#registration-correct-for-rigid-non-rigid-movement\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#initial-parameters\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">14.1. </span>Initial parameters<a class=\"headerlink\" href=\"#initial-parameters\" title=\"Permalink to this heading\">#</a></h2><p>In general in Caiman, estimators are first initialized with a set of parameters, and then they are fit against actual data in a separate step. In this section, we\u2019ll define a <code class=\"docutils literal notranslate\"><span class=\"pre\">parameters</span></code> object that will subsequently be used to initialize our different estimators.</p><p>The parameters are divided into different categories. We will not discuss them in detail in this section, but will go over them when needed (and note that in this notebook we will mostly focus on CNMF and later steps):</p>", "a[href=\"assembly.html#input-data-path-to-your-raw-tiff-file-s\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.2. </span>Input data: Path to your raw .tiff file(s)<a class=\"headerlink\" href=\"#input-data-path-to-your-raw-tiff-file-s\" title=\"Permalink to this heading\">#</a></h2><p>Before processing, ensure:</p>", "a[href=\"segmentation.html#pull-contours-good-components\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">22.1. </span>Pull contours / good components<a class=\"headerlink\" href=\"#pull-contours-good-components\" title=\"Permalink to this heading\">#</a></h2><p>View the diffs</p>", "a[href=\"collation.html#total-number-of-neurons\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25.2. </span>Total number of Neurons<a class=\"headerlink\" href=\"#total-number-of-neurons\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#cnmf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">14. </span>CNMF<a class=\"headerlink\" href=\"#cnmf\" title=\"Permalink to this heading\">#</a></h1><p>Perform CNMF using the mcorr output.</p><p>Similar to mcorr, put the CNMF params within the <code class=\"docutils literal notranslate\"><span class=\"pre\">main</span></code> key. The <code class=\"docutils literal notranslate\"><span class=\"pre\">refit</span></code> key will perform a second iteration, as shown in the <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code> <code class=\"docutils literal notranslate\"><span class=\"pre\">demo_pipeline.ipynb</span></code> notebook.</p>", "a[href=\"segmentation.html#load-outputs\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">24. </span>Load outputs<a class=\"headerlink\" href=\"#load-outputs\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"motion_correction.html#apply-registration-using-the-same-parameters-to-the-remaining-z-planes\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">10.2. </span>Apply registration using the same parameters to the remaining z-planes<a class=\"headerlink\" href=\"#apply-registration-using-the-same-parameters-to-the-remaining-z-planes\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#run-cnmf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">15. </span>Run CNMF<a class=\"headerlink\" href=\"#run-cnmf\" title=\"Permalink to this heading\">#</a></h1><p>The API is identical to running mcorr.</p><p>You can provide the mcorr item row to <code class=\"docutils literal notranslate\"><span class=\"pre\">input_movie_path</span></code> and it will resolve the path of the input movie from the entry in the DataFrame.</p>", "a[href=\"segmentation.html#temporal-components-residuals\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">17.1. </span>Temporal components, residuals<a class=\"headerlink\" href=\"#temporal-components-residuals\" title=\"Permalink to this heading\">#</a></h2><p>Many of the cnmf functions take a rich set of arguments</p>", "a[href=\"motion_correction.html#use-the-varients-to-organize-results-to-run-multiple-batch-items\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9. </span>Use the varients to organize results to run multiple batch items.<a class=\"headerlink\" href=\"#use-the-varients-to-organize-results-to-run-multiple-batch-items\" title=\"Permalink to this heading\">#</a></h1><p><code class=\"docutils literal notranslate\"><span class=\"pre\">df.iterrows()</span></code> iterates through rows and returns the numerical index and row for each iteration</p>", "a[href=\"collation.html#z-stack-alignment\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25.4. </span>z-stack alignment<a class=\"headerlink\" href=\"#z-stack-alignment\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"assembly.html#path-to-save-your-files\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.5. </span>Path to save your files<a class=\"headerlink\" href=\"#path-to-save-your-files\" title=\"Permalink to this heading\">#</a></h2><p>We can save the assembled image or individual ROIs to disk. The currently supported file extensions are <code class=\"docutils literal notranslate\"><span class=\"pre\">.tiff</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">.zarr</span></code>.</p>", "a[href=\"motion_correction.html#preview-motion-correction\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1. </span>Preview Motion Correction<a class=\"headerlink\" href=\"#preview-motion-correction\" title=\"Permalink to this heading\">#</a></h2><p>Before running a grid search for the best parameter set, preview your registration results</p>", "a[href=\"motion_correction.html#evaluate-results-optical-flow\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">10.1. </span>Evaluate Results: Optical Flow<a class=\"headerlink\" href=\"#evaluate-results-optical-flow\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"segmentation.html#batch-path-this-is-where-caiman-outputs-will-be-organized-same-as-the-previous-step\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">13.1. </span>Batch path, this is where caiman outputs will be organized, same as the previous step<a class=\"headerlink\" href=\"#batch-path-this-is-where-caiman-outputs-will-be-organized-same-as-the-previous-step\" title=\"Permalink to this heading\">#</a></h2><p>This can be anywhere, it does not need to be under the parent raw data path.</p>", "a[href=\"segmentation.html#using-lazyarrays\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">21. </span>Using LazyArrays<a class=\"headerlink\" href=\"#using-lazyarrays\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"assembly.html#preview-the-scanreader-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.4. </span>Preview the scanreader object<a class=\"headerlink\" href=\"#preview-the-scanreader-object\" title=\"Permalink to this heading\">#</a></h2><p>The scanreader object contains the following attributes:</p>", "a[href=\"#examples\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Examples<a class=\"headerlink\" href=\"#examples\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"preprocessing.html#correlation-max-images\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.4. </span>Correlation / Max Images<a class=\"headerlink\" href=\"#correlation-max-images\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4. </span>LBM Step 2: Registration<a class=\"headerlink\" href=\"#lbm-step-2-registration\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">4.1. </span>Registration: Correct for rigid/non-rigid movement<a class=\"headerlink\" href=\"#registration-correct-for-rigid-non-rigid-movement\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"motion_correction.html#optional-cleanup-dataframe\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">10. </span>Optional, cleanup DataFrame<a class=\"headerlink\" href=\"#optional-cleanup-dataframe\" title=\"Permalink to this heading\">#</a></h1><p>Use the index that works best and all other items.</p><p>Remove batch items (i.e. rows) using <code class=\"docutils literal notranslate\"><span class=\"pre\">df.caiman.remove_item(&lt;item_uuid&gt;)</span></code>. This also cleans up the output data in the batch directory.</p>", "a[href=\"segmentation.html#run-the-cnmf-batch-items\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">23. </span>Run the <code class=\"docutils literal notranslate\"><span class=\"pre\">cnmf</span></code> batch items<a class=\"headerlink\" href=\"#run-the-cnmf-batch-items\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"preprocessing.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2. </span>Preprocessing<a class=\"headerlink\" href=\"#preprocessing\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">2.1. </span>scanreader<a class=\"headerlink\" href=\"#scanreader\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"preprocessing.html#scanreader\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.1. </span>scanreader<a class=\"headerlink\" href=\"#scanreader\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"assembly.html#initialize-a-scanreader-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.3. </span>1. Initialize a scanreader object<a class=\"headerlink\" href=\"#initialize-a-scanreader-object\" title=\"Permalink to this heading\">#</a></h2><p>(Option 1). Simply pass a string containing a wildcard pattern for files to gather</p>", "a[href=\"segmentation.html#reconstructed-movie-a-c\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">18. </span>Reconstructed movie - <code class=\"docutils literal notranslate\"><span class=\"pre\">A</span> <span class=\"pre\">*</span> <span class=\"pre\">C</span></code><a class=\"headerlink\" href=\"#reconstructed-movie-a-c\" title=\"Permalink to this heading\">#</a></h1>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
